import pytest
import requests

def test_create_allergy_intolerance_valid_payload(<clinician_auth_headers>, <patient_id>, <base_url>):
    payload = {
        "resourceType": "AllergyIntolerance",
        "clinicalStatus": {
            "coding": [{"system": "http://terminology.hl7.org/CodeSystem/allergyintolerance-clinical", "code": "active"}]
        },
        "verificationStatus": {
            "coding": [{"system": "http://terminology.hl7.org/CodeSystem/allergyintolerance-verification", "code": "confirmed"}]
        },
        "code": {
            "coding": [{"system": "http://www.nlm.nih.gov/research/umls/rxnorm", "code": "7980"}],
            "text": "Penicillin"
        },
        "patient": {"reference": f"Patient/{<patient_id>}"}
    }
    resp = requests.post(
        f"{<base_url>}/AllergyIntolerance",
        json=payload,
        headers=<clinician_auth_headers>
    )
    assert resp.status_code == 201
    body = resp.json()
    assert body.get("resourceType") == "AllergyIntolerance"
    assert body.get("id"), "Resource id must be present"
    assert "Location" in resp.headers

